mapper.update:
UPDATE pet_health_record
record_date = #{recordDate}, height = #{height}, weight = #{weight}, temperature = #{temperature}, health_status = #{healthStatus}, diagnosis = #{diagnosis}, treatment = #{treatment}, doctor = #{doctor}, remark = #{remark},
WHERE id = #{id}

mapper.select:
SELECT h.id, DATE_FORMAT(h.record_date, '%Y-%m-%d') as recordDate, h.height, h.weight, h.temperature, h.health_status as healthStatus, h.diagnosis, h.treatment, h.doctor, h.remark, DATE_FORMAT(h.create_time, '%Y-%m-%d %H:%i:%s') as createTime, p.id as petId, p.name as petName, u.id as ownerId, u.username as ownerName FROM pet_health_record h LEFT JOIN pet_profile p ON h.pet_id = p.id LEFT JOIN user u ON p.user_id = u.id
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY h.create_time DESC LIMIT #{offset}, #{limit}
